114	const char *getenv_safe(struct strvec *argv, const char *name)
115	{
116		const char *value = getenv(name);
117	
118		if (!value)
119			return NULL;
120	
121		strvec_push(argv, value);
122		return argv->v[argv->nr - 1];
123	}
