151	const char *get_git_namespace(void)
152	{
153		static const char *namespace;
154		struct strbuf buf = STRBUF_INIT;
155		const char *raw_namespace;
156		struct string_list components = STRING_LIST_INIT_DUP;
157		struct string_list_item *item;
158	
159		if (namespace)
160			return namespace;
161	
162		raw_namespace = getenv(GIT_NAMESPACE_ENVIRONMENT);
163		if (!raw_namespace || !*raw_namespace) {
164			namespace = "";
165			return namespace;
166		}
167	
168		strbuf_addstr(&buf, raw_namespace);
169	
170		string_list_split(&components, buf.buf, "/", -1);
171		strbuf_reset(&buf);
172	
173		for_each_string_list_item(item, &components) {
174			if (item->string[0])
175				strbuf_addf(&buf, "refs/namespaces/%s/", item->string);
176		}
177		string_list_clear(&components, 0);
178	
179		strbuf_trim_trailing_dir_sep(&buf);
180		if (check_refname_format(buf.buf, 0))
181			die(_("bad git namespace path \"%s\""), raw_namespace);
182		strbuf_addch(&buf, '/');
183	
184		namespace = strbuf_detach(&buf, NULL);
185	
186		return namespace;
187	}
188	
189	const char *strip_namespace(const char *namespaced_ref)
190	{
191		const char *out;
192		if (skip_prefix(namespaced_ref, get_git_namespace(), &out))
193			return out;
194		return NULL;
195	}
