212	
213	int print_sha1_ellipsis(void)
214	{
215		/*
216		 * Determine if the calling environment contains the variable
217		 * GIT_PRINT_SHA1_ELLIPSIS set to "yes".
218		 */
219		static int cached_result = -1; /* unknown */
220	
221		if (cached_result < 0) {
222			const char *v = getenv("GIT_PRINT_SHA1_ELLIPSIS");
223			cached_result = (v && !strcasecmp(v, "yes"));
224		}
225		return cached_result;
226	}
227	
228	static const struct fsync_component_name {
229		const char *name;
230		enum fsync_component component_bits;
231	} fsync_component_names[] = {
232		{ "loose-object", FSYNC_COMPONENT_LOOSE_OBJECT },
233		{ "pack", FSYNC_COMPONENT_PACK },
234		{ "pack-metadata", FSYNC_COMPONENT_PACK_METADATA },
235		{ "commit-graph", FSYNC_COMPONENT_COMMIT_GRAPH },
236		{ "index", FSYNC_COMPONENT_INDEX },
237		{ "objects", FSYNC_COMPONENTS_OBJECTS },
238		{ "reference", FSYNC_COMPONENT_REFERENCE },
239		{ "derived-metadata", FSYNC_COMPONENTS_DERIVED_METADATA },
240		{ "committed", FSYNC_COMPONENTS_COMMITTED },
241		{ "added", FSYNC_COMPONENTS_ADDED },
242		{ "all", FSYNC_COMPONENTS_ALL },
243	};
244	
245	static enum fsync_component parse_fsync_components(const char *var, const char *string)
246	{
247		enum fsync_component current = FSYNC_COMPONENTS_PLATFORM_DEFAULT;
248		enum fsync_component positive = 0, negative = 0;
249	
250		while (string) {
251			size_t len;
252			const char *ep;
253			int negated = 0;
254			int found = 0;
255	
256			string = string + strspn(string, ", \t\n\r");
257			ep = strchrnul(string, ',');
258			len = ep - string;
259			if (!strcmp(string, "none")) {
260				current = FSYNC_COMPONENT_NONE;
261				goto next_name;
262			}
263	
264			if (*string == '-') {
265				negated = 1;
266				string++;
267				len--;
268				if (!len)
269					warning(_("invalid value for variable %s"), var);
270			}
271	
272			if (!len)
273				break;
274	
275			for (size_t i = 0; i < ARRAY_SIZE(fsync_component_names); ++i) {
276				const struct fsync_component_name *n = &fsync_component_names[i];
277	
278				if (strncmp(n->name, string, len))
279					continue;
280	
281				found = 1;
282				if (negated)
283					negative |= n->component_bits;
284				else
285					positive |= n->component_bits;
286			}
287	
288			if (!found) {
289				char *component = xstrndup(string, len);
290				warning(_("ignoring unknown core.fsync component '%s'"), component);
291				free(component);
292			}
293	
294	next_name:
295			string = ep;
296		}
297	
298		return (current & ~negative) | positive;
299	}
300	
301	int git_default_core_config(const char *var, const char *value,
302				    const struct config_context *ctx, void *cb)
303	{
304		struct repo_config_values *cfg = repo_config_values(the_repository);
305	
306		/* This needs a better name */
307		if (!strcmp(var, "core.filemode")) {
308			trust_executable_bit = git_config_bool(var, value);
309			return 0;
310		}
311		if (!strcmp(var, "core.trustctime")) {
312			cfg->trust_ctime = git_config_bool(var, value);
313			return 0;
314		}
315		if (!strcmp(var, "core.checkstat")) {
316			if (!value)
317				return config_error_nonbool(var);
318			if (!strcasecmp(value, "default"))
319				cfg->check_stat = 1;
320			else if (!strcasecmp(value, "minimal"))
321				cfg->check_stat = 0;
322			else
323				return error(_("invalid value for '%s': '%s'"),
324					     var, value);
325		}
326	
327		if (!strcmp(var, "core.quotepath")) {
328			quote_path_fully = git_config_bool(var, value);
329			return 0;
330		}
331	
332		if (!strcmp(var, "core.symlinks")) {
333			has_symlinks = git_config_bool(var, value);
334			return 0;
335		}
336	
337		if (!strcmp(var, "core.ignorecase")) {
338			ignore_case = git_config_bool(var, value);
339			return 0;
340		}
341	
342		if (!strcmp(var, "core.attributesfile")) {
343			FREE_AND_NULL(cfg->attributes_file);
344			return git_config_pathname(&cfg->attributes_file, var, value);
345		}
346	
347		if (!strcmp(var, "core.bare")) {
348			the_repository->bare_cfg = git_config_bool(var, value);
349			return 0;
350		}
351	
352		if (!strcmp(var, "core.ignorestat")) {
353			assume_unchanged = git_config_bool(var, value);
354			return 0;
355		}
356	
357		if (!strcmp(var, "core.abbrev")) {
358			if (!value)
359				return config_error_nonbool(var);
360			if (!strcasecmp(value, "auto"))
361				default_abbrev = -1;
362			else if (!git_parse_maybe_bool_text(value))
363				default_abbrev = GIT_MAX_HEXSZ;
364			else {
365				int abbrev = git_config_int(var, value, ctx->kvi);
366				if (abbrev < minimum_abbrev)
367					return error(_("abbrev length out of range: %d"), abbrev);
368				default_abbrev = abbrev;
369			}
370			return 0;
371		}
372	
373		if (!strcmp(var, "core.disambiguate"))
374			return set_disambiguate_hint_config(var, value);
375	
376		if (!strcmp(var, "core.loosecompression")) {
377			int level = git_config_int(var, value, ctx->kvi);
378			if (level == -1)
379				level = Z_DEFAULT_COMPRESSION;
380			else if (level < 0 || level > Z_BEST_COMPRESSION)
381				die(_("bad zlib compression level %d"), level);
382			cfg->zlib_compression_level = level;
383			zlib_compression_seen = 1;
384			return 0;
385		}
386	
387		if (!strcmp(var, "core.compression")) {
388			int level = git_config_int(var, value, ctx->kvi);
389			if (level == -1)
390				level = Z_DEFAULT_COMPRESSION;
391			else if (level < 0 || level > Z_BEST_COMPRESSION)
392				die(_("bad zlib compression level %d"), level);
393			if (!zlib_compression_seen)
394				cfg->zlib_compression_level = level;
395			if (!pack_compression_seen)
396				cfg->pack_compression_level = level;
397			return 0;
398		}
399	
400		if (!strcmp(var, "core.autocrlf")) {
401			if (value && !strcasecmp(value, "input")) {
402				auto_crlf = AUTO_CRLF_INPUT;
403				return 0;
404			}
405			auto_crlf = git_config_bool(var, value);
406			return 0;
407		}
408	
409		if (!strcmp(var, "core.safecrlf")) {
410			int eol_rndtrp_die;
411			if (value && !strcasecmp(value, "warn")) {
412				global_conv_flags_eol = CONV_EOL_RNDTRP_WARN;
413				return 0;
414			}
415			eol_rndtrp_die = git_config_bool(var, value);
416			global_conv_flags_eol = eol_rndtrp_die ?
417				CONV_EOL_RNDTRP_DIE : 0;
418			return 0;
419		}
420	
421		if (!strcmp(var, "core.eol")) {
422			if (value && !strcasecmp(value, "lf"))
423				core_eol = EOL_LF;
424			else if (value && !strcasecmp(value, "crlf"))
425				core_eol = EOL_CRLF;
426			else if (value && !strcasecmp(value, "native"))
427				core_eol = EOL_NATIVE;
428			else
429				core_eol = EOL_UNSET;
430			return 0;
431		}
432	
433		if (!strcmp(var, "core.checkroundtripencoding")) {
434			FREE_AND_NULL(check_roundtrip_encoding);
435			return git_config_string(&check_roundtrip_encoding, var, value);
436		}
437	
438		if (!strcmp(var, "core.editor")) {
439			FREE_AND_NULL(editor_program);
440			return git_config_string(&editor_program, var, value);
441		}
442	
443		if (!strcmp(var, "core.commentchar") ||
444		    !strcmp(var, "core.commentstring")) {
445			if (!value) {
446				return config_error_nonbool(var);
447	#ifndef WITH_BREAKING_CHANGES
448			} else if (!strcasecmp(value, "auto")) {
449				auto_comment_line_char = 1;
450				FREE_AND_NULL(comment_line_str_to_free);
451				comment_line_str = "#";
452	#endif /* !WITH_BREAKING_CHANGES */
453			} else if (value[0]) {
454				if (strchr(value, '\n'))
455					return error(_("%s cannot contain newline"), var);
456				comment_line_str = value;
457				FREE_AND_NULL(comment_line_str_to_free);
458	#ifndef WITH_BREAKING_CHANGES
459				auto_comment_line_char = 0;
460	#endif /* !WITH_BREAKING_CHANGES */
461			} else
462				return error(_("%s must have at least one character"), var);
463			return 0;
464		}
465	
466		if (!strcmp(var, "core.askpass")) {
467			FREE_AND_NULL(askpass_program);
468			return git_config_string(&askpass_program, var, value);
469		}
470	
471		if (!strcmp(var, "core.excludesfile")) {
472			FREE_AND_NULL(excludes_file);
473			return git_config_pathname(&excludes_file, var, value);
474		}
475	
476		if (!strcmp(var, "core.whitespace")) {
477			if (!value)
478				return config_error_nonbool(var);
479			whitespace_rule_cfg = parse_whitespace_rule(value);
480			return 0;
481		}
482	
483		if (!strcmp(var, "core.fsync")) {
484			if (!value)
485				return config_error_nonbool(var);
486			fsync_components = parse_fsync_components(var, value);
487			return 0;
488		}
489	
490		if (!strcmp(var, "core.fsyncmethod")) {
491			if (!value)
492				return config_error_nonbool(var);
493			if (!strcmp(value, "fsync"))
494				fsync_method = FSYNC_METHOD_FSYNC;
495			else if (!strcmp(value, "writeout-only"))
496				fsync_method = FSYNC_METHOD_WRITEOUT_ONLY;
497			else if (!strcmp(value, "batch"))
498				fsync_method = FSYNC_METHOD_BATCH;
499			else
500				warning(_("ignoring unknown core.fsyncMethod value '%s'"), value);
501	
502		}
503	
504		if (!strcmp(var, "core.fsyncobjectfiles")) {
505			if (fsync_object_files < 0)
506				warning(_("core.fsyncObjectFiles is deprecated; use core.fsync instead"));
507			fsync_object_files = git_config_bool(var, value);
508			return 0;
509		}
510	
511		if (!strcmp(var, "core.lockfilepid")) {
512			lockfile_pid_enabled = git_config_bool(var, value);
513			return 0;
514		}
515	
516		if (!strcmp(var, "core.createobject")) {
517			if (!value)
518				return config_error_nonbool(var);
519			if (!strcmp(value, "rename"))
520				object_creation_mode = OBJECT_CREATION_USES_RENAMES;
521			else if (!strcmp(value, "link"))
522				object_creation_mode = OBJECT_CREATION_USES_HARDLINKS;
523			else
524				die(_("invalid mode for object creation: %s"), value);
525			return 0;
526		}
527	
528		if (!strcmp(var, "core.sparsecheckout")) {
529			cfg->apply_sparse_checkout = git_config_bool(var, value);
530			return 0;
531		}
532	
533		if (!strcmp(var, "core.sparsecheckoutcone")) {
534			cfg->core_sparse_checkout_cone = git_config_bool(var, value);
535			return 0;
536		}
537	
538		if (!strcmp(var, "core.precomposeunicode")) {
539			cfg->precomposed_unicode = git_config_bool(var, value);
540			return 0;
541		}
542	
543		if (!strcmp(var, "core.protecthfs")) {
544			cfg->protect_hfs = git_config_bool(var, value);
545			return 0;
546		}
547	
548		if (!strcmp(var, "core.protectntfs")) {
549			cfg->protect_ntfs = git_config_bool(var, value);
550			return 0;
551		}
552	
553		/* Add other config variables here and to Documentation/config.adoc. */
554		return platform_core_config(var, value, ctx, cb);
555	}
556	
557	static int git_default_sparse_config(const char *var, const char *value)
558	{
559		struct repo_config_values *cfg = repo_config_values(the_repository);
560	
561		if (!strcmp(var, "sparse.expectfilesoutsideofpatterns")) {
562			cfg->sparse_expect_files_outside_of_patterns = git_config_bool(var, value);
563			return 0;
564		}
565	
566		/* Add other config variables here and to Documentation/config/sparse.adoc. */
567		return 0;
568	}
569	
570	static int git_default_i18n_config(const char *var, const char *value)
571	{
572		if (!strcmp(var, "i18n.commitencoding")) {
573			FREE_AND_NULL(git_commit_encoding);
574			return git_config_string(&git_commit_encoding, var, value);
575		}
576	
577		if (!strcmp(var, "i18n.logoutputencoding")) {
578			FREE_AND_NULL(git_log_output_encoding);
579			return git_config_string(&git_log_output_encoding, var, value);
580		}
581	
582		/* Add other config variables here and to Documentation/config.adoc. */
583		return 0;
584	}
585	
586	static int git_default_branch_config(const char *var, const char *value)
587	{
588		struct repo_config_values *cfg = repo_config_values(the_repository);
589	
590		if (!strcmp(var, "branch.autosetupmerge")) {
591			if (value && !strcmp(value, "always")) {
592				cfg->branch_track = BRANCH_TRACK_ALWAYS;
593				return 0;
594			} else if (value && !strcmp(value, "inherit")) {
595				cfg->branch_track = BRANCH_TRACK_INHERIT;
596				return 0;
597			} else if (value && !strcmp(value, "simple")) {
598				cfg->branch_track = BRANCH_TRACK_SIMPLE;
599				return 0;
600			}
601			cfg->branch_track = git_config_bool(var, value);
602			return 0;
603		}
604		if (!strcmp(var, "branch.autosetuprebase")) {
605			if (!value)
606				return config_error_nonbool(var);
607			else if (!strcmp(value, "never"))
608				autorebase = AUTOREBASE_NEVER;
609			else if (!strcmp(value, "local"))
610				autorebase = AUTOREBASE_LOCAL;
611			else if (!strcmp(value, "remote"))
612				autorebase = AUTOREBASE_REMOTE;
613			else if (!strcmp(value, "always"))
614				autorebase = AUTOREBASE_ALWAYS;
615			else
616				return error(_("malformed value for %s"), var);
617			return 0;
618		}
619	
620		/* Add other config variables here and to Documentation/config.adoc. */
621		return 0;
622	}
623	
624	static int git_default_push_config(const char *var, const char *value)
625	{
626		if (!strcmp(var, "push.default")) {
627			if (!value)
628				return config_error_nonbool(var);
629			else if (!strcmp(value, "nothing"))
630				push_default = PUSH_DEFAULT_NOTHING;
631			else if (!strcmp(value, "matching"))
632				push_default = PUSH_DEFAULT_MATCHING;
633			else if (!strcmp(value, "simple"))
634				push_default = PUSH_DEFAULT_SIMPLE;
635			else if (!strcmp(value, "upstream"))
636				push_default = PUSH_DEFAULT_UPSTREAM;
637			else if (!strcmp(value, "tracking")) /* deprecated */
638				push_default = PUSH_DEFAULT_UPSTREAM;
639			else if (!strcmp(value, "current"))
640				push_default = PUSH_DEFAULT_CURRENT;
641			else {
642				error(_("malformed value for %s: %s"), var, value);
643				return error(_("must be one of nothing, matching, simple, "
644					       "upstream or current"));
645			}
646			return 0;
647		}
648	
649		/* Add other config variables here and to Documentation/config.adoc. */
650		return 0;
651	}
652	
653	static int git_default_attr_config(const char *var, const char *value)
654	{
655		if (!strcmp(var, "attr.tree")) {
656			FREE_AND_NULL(git_attr_tree);
657			return git_config_string(&git_attr_tree, var, value);
658		}
659	
660		/*
661		 * Add other attribute related config variables here and to
662		 * Documentation/config/attr.adoc.
663		 */
664		return 0;
665	}
666	
667	int git_default_config(const char *var, const char *value,
668			       const struct config_context *ctx, void *cb)
669	{
670		struct repo_config_values *cfg = repo_config_values(the_repository);
671	
672		if (starts_with(var, "core."))
673			return git_default_core_config(var, value, ctx, cb);
674	
675		if (starts_with(var, "user.") ||
676		    starts_with(var, "author.") ||
677		    starts_with(var, "committer."))
678			return git_ident_config(var, value, ctx, cb);
679	
680		if (starts_with(var, "i18n."))
681			return git_default_i18n_config(var, value);
682	
683		if (starts_with(var, "branch."))
684			return git_default_branch_config(var, value);
685	
686		if (starts_with(var, "push."))
687			return git_default_push_config(var, value);
688	
689		if (starts_with(var, "attr."))
690			return git_default_attr_config(var, value);
691	
692		if (starts_with(var, "advice.") || starts_with(var, "color.advice"))
693			return git_default_advice_config(var, value);
694	
695		if (!strcmp(var, "pager.color") || !strcmp(var, "color.pager")) {
696			pager_use_color = git_config_bool(var,value);
697			return 0;
698		}
699	
700		if (!strcmp(var, "pack.packsizelimit")) {
701			pack_size_limit_cfg = git_config_ulong(var, value, ctx->kvi);
702			return 0;
703		}
704	
705		if (!strcmp(var, "pack.compression")) {
706			int level = git_config_int(var, value, ctx->kvi);
707			if (level == -1)
708				level = Z_DEFAULT_COMPRESSION;
709			else if (level < 0 || level > Z_BEST_COMPRESSION)
710				die(_("bad pack compression level %d"), level);
711			cfg->pack_compression_level = level;
712			pack_compression_seen = 1;
713			return 0;
714		}
715	
716		if (starts_with(var, "sparse."))
717			return git_default_sparse_config(var, value);
718	
719		/* Add other config variables here and to Documentation/config.adoc. */
720		return 0;
721	}
722	
723	void repo_config_values_init(struct repo_config_values *cfg)
724	{
725		cfg->attributes_file = NULL;
726		cfg->apply_sparse_checkout = 0;
727		cfg->protect_hfs = PROTECT_HFS_DEFAULT;
728		cfg->protect_ntfs = PROTECT_NTFS_DEFAULT;
729		cfg->branch_track = BRANCH_TRACK_REMOTE;
730		cfg->trust_ctime = 1;
731		cfg->check_stat = 1;
732		cfg->zlib_compression_level = Z_BEST_SPEED;
733		cfg->pack_compression_level = Z_DEFAULT_COMPRESSION;
734		cfg->precomposed_unicode = -1; /* see probe_utf8_pathname_composition() */
735		cfg->core_sparse_checkout_cone = 0;
736		cfg->sparse_expect_files_outside_of_patterns = 0;
737		cfg->warn_on_object_refname_ambiguity = 1;
738	}
