642	void kvi_from_param(struct key_value_info *out)
643	{
644		out->filename = NULL;
645		out->linenr = -1;
646		out->origin_type = CONFIG_ORIGIN_CMDLINE;
647		out->scope = CONFIG_SCOPE_COMMAND;
